     8→public abstract class OrderStatus : SmartEnum<OrderStatus>
     9→{
    10→    // Happy path states
    11→    public static readonly OrderStatus Submitted     = new SubmittedStatus();
    12→    public static readonly OrderStatus StockReserved = new StockReservedStatus();
    13→    public static readonly OrderStatus Paid          = new PaidStatus();
    14→    public static readonly OrderStatus Confirmed     = new ConfirmedStatus();
    15→    public static readonly OrderStatus Shipped       = new ShippedStatus();
    16→    public static readonly OrderStatus Delivered     = new DeliveredStatus();
    17→    // Terminal non-happy states
    18→    public static readonly OrderStatus Failed        = new FailedStatus();
    19→    public static readonly OrderStatus Cancelled     = new CancelledStatus();
    20→
    21→    private OrderStatus(string name, int value) : base(name, value) { }
    22→
    23→    public abstract bool CanTransitionTo(OrderStatus next);
    24→
    25→    public void TransitionTo(OrderStatus next)
    26→    {
    27→        if (!CanTransitionTo(next))
    28→        {
    29→            IEnumerable<string> validNames = List.Where(s => CanTransitionTo(s)).Select(s => s.Name);
    30→            throw new InvalidOperationException(
    31→                $"Cannot transition from '{Name}' to '{next.Name}'. " +
    32→                $"Valid transitions from '{Name}': {string.Join(", ", validNames)}.");
    33→        }
