using System.Net;
using System.Net.Http.Json;
using FluentAssertions;
using MicroCommerce.ApiService.Features.Ordering.Infrastructure;
using MicroCommerce.ApiService.Features.Profiles.Infrastructure;
using MicroCommerce.ApiService.Features.Reviews.Application.Queries.GetReviewsByProduct;
using MicroCommerce.ApiService.Features.Reviews.Infrastructure;
using MicroCommerce.ApiService.Tests.Integration.Builders;
using MicroCommerce.ApiService.Tests.Integration.Fixtures;
using Microsoft.Extensions.DependencyInjection;

namespace MicroCommerce.ApiService.Tests.Integration.Reviews;

[Collection("Integration Tests")]
[Trait("Category", "Integration")]
public sealed class ReviewsEndpointsTests : IntegrationTestBase
{
    public ReviewsEndpointsTests(ApiWebApplicationFactory factory)
        : base(factory)
    {
    }

    public override async Task InitializeAsync()
    {
        await ResetDatabase(
            typeof(ReviewsDbContext),
            typeof(OrderingDbContext),
            typeof(ProfilesDbContext));
    }

    [Fact]
    public async Task GetProductReviews_NoReviews_ReturnsEmptyList()
    {
        // Arrange - Use guest client (public endpoint, no auth required)
        HttpClient client = CreateGuestClient();
        Guid productId = Guid.NewGuid();

        // Act
        ReviewListDto? result = await client.GetFromJsonAsync<ReviewListDto>(
            $"/api/reviews/products/{productId}");

        // Assert
        result.Should().NotBeNull();
        result!.Items.Should().BeEmpty();
        result.TotalCount.Should().Be(0);
    }

    [Fact]
    public async Task CanReview_WithoutPurchase_ReturnsFalseForHasPurchased()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.GetAsync($"/api/reviews/products/{productId}/can-review");

        // Assert
        response.IsSuccessStatusCode.Should().BeTrue();
        string body = await response.Content.ReadAsStringAsync();
        using System.Text.Json.JsonDocument doc = System.Text.Json.JsonDocument.Parse(body);
        doc.RootElement.GetProperty("hasPurchased").GetBoolean().Should().BeFalse();
        doc.RootElement.GetProperty("hasReviewed").GetBoolean().Should().BeFalse();
    }

    [Fact]
    public async Task CanReview_WithPaidOrder_ReturnsTrueForHasPurchased()
    {
        // Arrange - Seed a Paid order for the user containing the product
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        await SeedPaidOrderAsync(userId, productId);

        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.GetAsync($"/api/reviews/products/{productId}/can-review");

        // Assert
        response.IsSuccessStatusCode.Should().BeTrue();
        string body = await response.Content.ReadAsStringAsync();
        using System.Text.Json.JsonDocument doc = System.Text.Json.JsonDocument.Parse(body);
        doc.RootElement.GetProperty("hasPurchased").GetBoolean().Should().BeTrue();
    }

    [Fact]
    public async Task CreateReview_WithVerifiedPurchase_ReturnsCreated()
    {
        // Arrange - User must have purchased the product
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        await SeedPaidOrderAsync(userId, productId);

        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 5, Text = "Excellent product, highly recommend!" });

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.Created);
        string body = await response.Content.ReadAsStringAsync();
        using System.Text.Json.JsonDocument doc = System.Text.Json.JsonDocument.Parse(body);
        doc.RootElement.GetProperty("id").GetGuid().Should().NotBeEmpty();
    }

    [Fact]
    public async Task CreateReview_WithoutPurchase_ReturnsBadRequest()
    {
        // Arrange - User has NOT purchased the product
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 4, Text = "Good product." });

        // Assert - InvalidOperationException -> 400
        response.StatusCode.Should().Be(HttpStatusCode.BadRequest);
    }

    [Fact]
    public async Task GetMyReview_AfterCreatingReview_ReturnsReview()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        await SeedPaidOrderAsync(userId, productId);

        HttpClient client = CreateAuthenticatedClient(userId);
        await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 4, Text = "Very good." });

        // Act
        HttpResponseMessage response = await client.GetAsync($"/api/reviews/products/{productId}/mine");

        // Assert
        response.IsSuccessStatusCode.Should().BeTrue();
        ReviewDto? review = await response.Content.ReadFromJsonAsync<ReviewDto>();
        review.Should().NotBeNull();
        review!.UserId.Should().Be(userId);
        review.Rating.Should().Be(4);
        review.Text.Should().Be("Very good.");
    }

    [Fact]
    public async Task GetMyReview_WhenNoReviewExists_ReturnsNotFound()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.GetAsync($"/api/reviews/products/{productId}/mine");

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NotFound);
    }

    [Fact]
    public async Task UpdateReview_AsOwner_ReturnsNoContent()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        await SeedPaidOrderAsync(userId, productId);

        HttpClient client = CreateAuthenticatedClient(userId);
        HttpResponseMessage createResponse = await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 3, Text = "Average." });
        string createBody = await createResponse.Content.ReadAsStringAsync();
        using System.Text.Json.JsonDocument doc = System.Text.Json.JsonDocument.Parse(createBody);
        Guid reviewId = doc.RootElement.GetProperty("id").GetGuid();

        // Act
        HttpResponseMessage response = await client.PutAsJsonAsync(
            $"/api/reviews/{reviewId}",
            new { Rating = 5, Text = "Actually amazing!" });

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NoContent);
    }

    [Fact]
    public async Task UpdateReview_NonExistentReview_ReturnsNotFound()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.PutAsJsonAsync(
            $"/api/reviews/{Guid.NewGuid()}",
            new { Rating = 5, Text = "Amazing!" });

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NotFound);
    }

    [Fact]
    public async Task DeleteReview_AsOwner_ReturnsNoContent()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        await SeedPaidOrderAsync(userId, productId);

        HttpClient client = CreateAuthenticatedClient(userId);
        HttpResponseMessage createResponse = await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 5, Text = "Great!" });
        string createBody = await createResponse.Content.ReadAsStringAsync();
        using System.Text.Json.JsonDocument doc = System.Text.Json.JsonDocument.Parse(createBody);
        Guid reviewId = doc.RootElement.GetProperty("id").GetGuid();

        // Act
        HttpResponseMessage response = await client.DeleteAsync($"/api/reviews/{reviewId}");

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NoContent);
    }

    [Fact]
    public async Task DeleteReview_NonExistentReview_ReturnsNotFound()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.DeleteAsync($"/api/reviews/{Guid.NewGuid()}");

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NotFound);
    }

    [Fact]
    public async Task CreateReview_DuplicateReview_ReturnsConflict()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        await SeedPaidOrderAsync(userId, productId);

        HttpClient client = CreateAuthenticatedClient(userId);
        await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 5, Text = "First review." });

        // Act - submit a second review for the same product
        HttpResponseMessage response = await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 4, Text = "Second review attempt." });

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.Conflict);
    }

    /// <summary>
    /// Seeds an Order in Paid status for the given buyer containing the given product.
    /// Required for review endpoints that check verified purchase.
    /// </summary>
    private async Task SeedPaidOrderAsync(Guid buyerId, Guid productId)
    {
        using IServiceScope scope = CreateScope();
        OrderingDbContext db = scope.ServiceProvider.GetRequiredService<OrderingDbContext>();

        Features.Ordering.Domain.Entities.Order order = new OrderBuilder()
            .WithBuyerId(buyerId)
            .WithItem(productId, "Test Product", 29.99m, null, 1)
            .Build();

        order.MarkAsPaid();

        db.Orders.Add(order);
        await db.SaveChangesAsync();
    }
}

