        HttpResponseMessage createResponse = await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 3, Text = "Average." });
        string createBody = await createResponse.Content.ReadAsStringAsync();
        using System.Text.Json.JsonDocument doc = System.Text.Json.JsonDocument.Parse(createBody);
        Guid reviewId = doc.RootElement.GetProperty("id").GetGuid();

        // Act
        HttpResponseMessage response = await client.PutAsJsonAsync(
            $"/api/reviews/{reviewId}",
            new { Rating = 5, Text = "Actually amazing!" });

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NoContent);
    }

    [Fact]
    public async Task UpdateReview_NonExistentReview_ReturnsNotFound()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.PutAsJsonAsync(
            $"/api/reviews/{Guid.NewGuid()}",
            new { Rating = 5, Text = "Amazing!" });

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NotFound);
    }

    [Fact]
    public async Task DeleteReview_AsOwner_ReturnsNoContent()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        await SeedPaidOrderAsync(userId, productId);

        HttpClient client = CreateAuthenticatedClient(userId);
        HttpResponseMessage createResponse = await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 5, Text = "Great!" });
        string createBody = await createResponse.Content.ReadAsStringAsync();
        using System.Text.Json.JsonDocument doc = System.Text.Json.JsonDocument.Parse(createBody);
        Guid reviewId = doc.RootElement.GetProperty("id").GetGuid();

        // Act
        HttpResponseMessage response = await client.DeleteAsync($"/api/reviews/{reviewId}");

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NoContent);
    }

    [Fact]
    public async Task DeleteReview_NonExistentReview_ReturnsNotFound()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        HttpClient client = CreateAuthenticatedClient(userId);

        // Act
        HttpResponseMessage response = await client.DeleteAsync($"/api/reviews/{Guid.NewGuid()}");

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.NotFound);
    }

    [Fact]
    public async Task CreateReview_DuplicateReview_ReturnsConflict()
    {
        // Arrange
        Guid userId = Guid.NewGuid();
        Guid productId = Guid.NewGuid();
        await SeedPaidOrderAsync(userId, productId);

        HttpClient client = CreateAuthenticatedClient(userId);
        await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 5, Text = "First review." });

        // Act - submit a second review for the same product
        HttpResponseMessage response = await client.PostAsJsonAsync(
            $"/api/reviews/products/{productId}",
            new { Rating = 4, Text = "Second review attempt." });

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.Conflict);
    }

    /// <summary>
    /// Seeds an Order in Paid status for the given buyer containing the given product.
    /// Required for review endpoints that check verified purchase.
    /// </summary>
    private async Task SeedPaidOrderAsync(Guid buyerId, Guid productId)
    {
        using IServiceScope scope = CreateScope();
        OrderingDbContext db = scope.ServiceProvider.GetRequiredService<OrderingDbContext>();

        Features.Ordering.Domain.Entities.Order order = new OrderBuilder()
            .WithBuyerId(buyerId)
            .WithItem(productId, "Test Product", 29.99m, null, 1)
            .Build();

        order.MarkAsPaid();

        db.Orders.Add(order);
        await db.SaveChangesAsync();
    }
}

